def generate_thumbnail(
    self, image_path: Path, max_size: tuple = (256, 256)
) -> Optional[Path]:
    """Generate a thumbnail for a single image."""
    try:
        from PIL import Image
        img = Image.open(image_path)
        img.thumbnail(max_size)
        output_path = self.output_dir / f"thumb_{image_path.name}"
        img.save(output_path)
        return output_path
    except Exception as e:
        print(f"Error processing {image_path}: {e}")
        return None

def generate_all_thumbnails(self, max_size: tuple = (256, 256)) -> list:
    """Generate thumbnails for all images in input directory."""
    results = []
    for img_path in self.list_images():
        result = self.generate_thumbnail(img_path, max_size)
        if result:
            results.append(result)
    return results
